import shlex

def executeCommand():
    command = input("Enter command: ")
    try:
        parts = shlex.split(command)
    except ValueError:
        print("Invalid command format.")
        return
    if not parts:
        print("No command entered.")
        return
    # Whitelist allowed commands with full paths
    allowed_commands = {
        'ls': '/bin/ls',
        'pwd': '/bin/pwd',
        'whoami': '/usr/bin/whoami'
    }
    if parts[0] not in allowed_commands:
        print("Command not allowed.")
        return
    # Replace command name with full path
    parts[0] = allowed_commands[parts[0]]
    try:
        subprocess.run(parts, check=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, shell=False)
    except subprocess.CalledProcessError as e:
        print(f"Command failed: {e}")
    except Exception as e:
        print(f"Error: {e}")

from flask import Flask, request
app = Flask(__name__)

@app.route("/evalcode")
def eval_code():
    user_input = request.args.get('code')
    if not user_input:
        return 'No code provided', 400
    try:
        code_obj = compile(user_input, '<string>', 'exec')
    except SyntaxError:
        return 'Invalid syntax', 400
    safe_globals = {'__builtins__': {}}  # restrict builtins
    safe_globals['__builtins__']['print'] = print  # allow print
    try:
        exec(code_obj, safe_globals)
        return 'Code executed successfully', 200
    except Exception as e:
        return f'Error: {str(e)}', 500

