import base64
import json


def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token).decode('utf-8')
        token = json.loads(decoded)
        return token
    except (base64.binascii.Error, UnicodeDecodeError, json.JSONDecodeError):
        return None
